mapper.sql:
from t_pay_order po
LEFT JOIN t_waybill wb on wb.waybill_id = po.waybill_id

    LEFT JOIN t_flow_instance_task_record fr ON fr.instance_id = po.flow_instance_id


    LEFT JOIN t_flow_instance fi ON fi.instance_id = po.flow_instance_id



        AND (INSTR(po.pay_order_number,#{queryForm.keywords}) OR
        INSTR(wb.waybill_number,#{queryForm.keywords}) OR
        INSTR(wb.container_number,#{queryForm.keywords}) OR
        INSTR(po.remark,#{queryForm.keywords})
        )


        and wb.waybill_number IN

            #{item}



        AND po.pay_order_type = #{queryForm.payOrderType}


        AND po.pay_order_status = #{queryForm.payOrderStatus}


        AND po.verification_flag = #{queryForm.verificationFlag}


        AND po.shipper_id = #{queryForm.shipperId}


        AND po.driver_id = #{queryForm.driverId}


        AND po.vehicle_id = #{queryForm.vehicleId}


        AND po.fleet_id = #{queryForm.fleetId}


        and DATE_FORMAT(po.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        and DATE_FORMAT(po.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        and DATE_FORMAT(po.pay_time, '%Y-%m-%d') >= #{queryForm.payStartTime}


        and DATE_FORMAT(po.pay_time, '%Y-%m-%d') <= #{queryForm.payEndTime}



        and po.pay_order_status != #{queryForm.excludePayOrderStatus}


        and po.enterprise_id = #{queryForm.enterpriseId}


        and po.create_user_id = #{queryForm.createUserId}


        and po.audit_status = #{queryForm.auditStatus}


        and po.audit_status in

            #{item}



        and fr.handler = #{queryForm.requestUserId}


        and FIND_IN_SET(#{queryForm.requestUserId},fi.current_handlers)



    GROUP BY po.flow_instance_id


    order by po.pay_order_id desc

