SELECT po.pay_order_id,
po.payable_total_amount,
o.create_user_id customerServiceId
FROM t_pay_order po
LEFT JOIN t_waybill w ON w.waybill_id = po.waybill_id
LEFT JOIN t_order o ON o.order_id = w.order_id


        po.pay_order_status != #{queryForm.excludePayOrderStatus}


        AND DATE_FORMAT(po.create_time, '%Y-%m-%d') >= #{queryForm.startDate}


        AND DATE_FORMAT(po.create_time, '%Y-%m-%d') <= #{queryForm.endDate}


        AND o.create_user_id IN

